package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // Override read() to call super.read() on the Reader (simulate BufferedReader behavior)
            @Override
            public int read() throws IOException {
                return super.read();
            }
        };
    }

    @Test
    void testRead_notNewLine() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        // Because super.read() calls underlying Reader.read(), we mock that:
        when(mockReader.read()).thenReturn((int) 'a');

        int result = spyReader.read();

        assertEquals('a', result);
        // lineCounter should remain 0
        assertEquals(0, getPrivateField(spyReader, "lineCounter"));
        // lastChar should be 'a'
        assertEquals('a', getPrivateField(spyReader, "lastChar"));
    }

    @Test
    void testRead_newLine() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        when(mockReader.read()).thenReturn((int) '\n');

        int result = spyReader.read();

        assertEquals('\n', result);
        // lineCounter should be incremented to 1
        assertEquals(1, getPrivateField(spyReader, "lineCounter"));
        // lastChar should be '\n'
        assertEquals('\n', getPrivateField(spyReader, "lastChar"));
    }

    @Test
    void testRead_endOfStream() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        when(mockReader.read()).thenReturn(-1);

        int result = spyReader.read();

        assertEquals(-1, result);
        // lineCounter should remain 0
        assertEquals(0, getPrivateField(spyReader, "lineCounter"));
        // lastChar should be -1 (END_OF_STREAM)
        assertEquals(-1, getPrivateField(spyReader, "lastChar"));
    }

    private int getPrivateField(ExtendedBufferedReader instance, String fieldName) {
        try {
            Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getInt(instance);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
